package com.pedrodalben.bigbangeventos.ranking;
import com.pedrodalben.bigbangeventos.participant.EventParticipant; import com.pedrodalben.bigbangeventos.session.EventSession; import java.util.*;
public enum Rankings implements RankingStrategy { SCORE_DESCENDING { public List<EventParticipant> rank(EventSession s){return sorted(s,Comparator.<EventParticipant>comparingInt(EventParticipant::score).reversed());}}, TIME_ASCENDING { public List<EventParticipant> rank(EventSession s){return sorted(s,Comparator.comparing((EventParticipant p)->p.finishedAt().orElse(java.time.Instant.MAX)));}}, COMPLETION_ORDER { public List<EventParticipant> rank(EventSession s){return sorted(s,Comparator.comparing((EventParticipant p)->p.finishedAt().orElse(java.time.Instant.MAX)));}}; private static List<EventParticipant> sorted(EventSession s,Comparator<EventParticipant> c){List<EventParticipant>r=new ArrayList<>(s.participants());r.sort(c);for(int i=0;i<r.size();i++)r.get(i).position(i+1);return List.copyOf(r);} }
